import { useState } from 'react';
import { 
  Plus, 
  Search, 
  Filter, 
  Download,
  Smartphone,
  AlertCircle
} from 'lucide-react';
import type { View } from '@/types/view';

interface TicketListProps {
  onNavigate: (view: View, id?: string) => void;
}

const mockTickets = [
  { id: 'TK-2024-1247', customer: 'John Smith', device: 'MacBook Pro 16"', type: 'laptop', status: 'diagnosis', priority: 'high', sla: 'express', created: '2024-12-09 09:30', deadline: '2h' },
  { id: 'TK-2024-1246', customer: 'Sarah Johnson', device: 'iPhone 14 Pro', type: 'phone', status: 'repair', priority: 'medium', sla: 'standard', created: '2024-12-09 08:15', deadline: '1d' },
  { id: 'TK-2024-1245', customer: 'Mike Wilson', device: 'Dell XPS 15', type: 'laptop', status: 'testing', priority: 'low', sla: 'standard', created: '2024-12-08 16:45', deadline: '8h' },
  { id: 'TK-2024-1244', customer: 'Emma Davis', device: 'Samsung Galaxy S23', type: 'phone', status: 'ready', priority: 'high', sla: 'vip', created: '2024-12-08 14:20', deadline: 'OK' },
  { id: 'TK-2024-1243', customer: 'Robert Brown', device: 'HP Pavilion', type: 'laptop', status: 'new', priority: 'medium', sla: 'warranty', created: '2024-12-08 11:00', deadline: '2d' },
  { id: 'TK-2024-1242', customer: 'Lisa Anderson', device: 'PlayStation 5', type: 'console', status: 'repair', priority: 'low', sla: 'standard', created: '2024-12-07 15:30', deadline: '1d' },
  { id: 'TK-2024-1241', customer: 'Tom Martinez', device: 'iMac 27"', type: 'pc', status: 'delivered', priority: 'medium', sla: 'express', created: '2024-12-06 10:00', deadline: 'Complete' },
  { id: 'TK-2024-1240', customer: 'Alice Cooper', device: 'Google Pixel 8', type: 'phone', status: 'diagnosis', priority: 'high', sla: 'vip', created: '2024-12-09 07:00', deadline: '30m' },
];

export function TicketList({ onNavigate }: TicketListProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [priorityFilter, setPriorityFilter] = useState('all');

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'new': return 'bg-[#00D9FF]/10 text-[#00D9FF] border-[#00D9FF]/20';
      case 'diagnosis': return 'bg-[#A78BFA]/10 text-[#A78BFA] border-[#A78BFA]/20';
      case 'repair': return 'bg-[#FF6B35]/10 text-[#FF6B35] border-[#FF6B35]/20';
      case 'testing': return 'bg-[#FFB800]/10 text-[#FFB800] border-[#FFB800]/20';
      case 'ready': return 'bg-[#00FF88]/10 text-[#00FF88] border-[#00FF88]/20';
      case 'delivered': return 'bg-[#64748B]/10 text-[#64748B] border-[#64748B]/20';
      default: return 'bg-[#64748B]/10 text-[#64748B] border-[#64748B]/20';
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high': return 'bg-[#FF6B35]';
      case 'medium': return 'bg-[#FFB800]';
      case 'low': return 'bg-[#00D9FF]';
      default: return 'bg-[#64748B]';
    }
  };

  const getDeadlineColor = (deadline: string) => {
    if (deadline.includes('m') || (deadline.includes('h') && parseInt(deadline) < 4)) {
      return 'text-[#FF6B35]';
    }
    if (deadline.includes('h') || deadline === '1d') {
      return 'text-[#FFB800]';
    }
    return 'text-[#00FF88]';
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-white text-2xl mb-1">Ticket Management</h1>
          <p className="text-[#94A3B8]">Manage and track repair tickets</p>
        </div>
        <button
          onClick={() => onNavigate('new-ticket')}
          className="px-6 py-3 bg-gradient-to-r from-[#00FF88] to-[#00CC6A] text-[#0C1222] rounded-lg hover:scale-105 transition-transform flex items-center gap-2"
        >
          <Plus className="w-5 h-5" />
          New Ticket
        </button>
      </div>

      {/* Filters */}
      <div className="bg-[#0C1222] rounded-xl p-6 border border-[#1A2642] shadow-lg">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div className="md:col-span-2">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-[#64748B]" />
              <input
                type="text"
                placeholder="Search by ticket ID, customer, or device..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-[#121B2D] border border-[#1A2642] rounded-lg text-white placeholder-[#64748B] focus:outline-none focus:border-[#00FF88] transition-colors"
              />
            </div>
          </div>
          <div>
            <select
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value)}
              className="w-full px-4 py-3 bg-[#121B2D] border border-[#1A2642] rounded-lg text-white focus:outline-none focus:border-[#00FF88] transition-colors"
            >
              <option value="all">All Statuses</option>
              <option value="new">New</option>
              <option value="diagnosis">Diagnosis</option>
              <option value="repair">Repair</option>
              <option value="testing">Testing</option>
              <option value="ready">Ready</option>
              <option value="delivered">Delivered</option>
            </select>
          </div>
          <div>
            <select
              value={priorityFilter}
              onChange={(e) => setPriorityFilter(e.target.value)}
              className="w-full px-4 py-3 bg-[#121B2D] border border-[#1A2642] rounded-lg text-white focus:outline-none focus:border-[#00FF88] transition-colors"
            >
              <option value="all">All Priorities</option>
              <option value="high">High</option>
              <option value="medium">Medium</option>
              <option value="low">Low</option>
            </select>
          </div>
        </div>
        <div className="flex items-center gap-3 mt-4 pt-4 border-t border-[#1A2642]">
          <button className="px-4 py-2 bg-[#121B2D] border border-[#1A2642] rounded-lg text-[#94A3B8] hover:text-white hover:border-[#00FF88] transition-colors flex items-center gap-2">
            <Filter className="w-4 h-4" />
            More Filters
          </button>
          <button className="px-4 py-2 bg-[#121B2D] border border-[#1A2642] rounded-lg text-[#94A3B8] hover:text-white hover:border-[#00FF88] transition-colors flex items-center gap-2">
            <Download className="w-4 h-4" />
            Export
          </button>
          <div className="ml-auto text-[#94A3B8] text-sm">
            {mockTickets.length} tickets found
          </div>
        </div>
      </div>

      {/* Tickets Table */}
      <div className="bg-[#0C1222] rounded-xl border border-[#1A2642] shadow-lg overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead>
              <tr className="border-b border-[#1A2642]">
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Ticket ID</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Customer</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Device</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Status</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Priority</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">SLA Type</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Deadline</th>
                <th className="text-left px-6 py-4 text-[#94A3B8] text-sm">Created</th>
              </tr>
            </thead>
            <tbody>
              {mockTickets.map((ticket) => (
                <tr
                  key={ticket.id}
                  onClick={() => onNavigate('ticket-detail', ticket.id)}
                  className="border-b border-[#1A2642] hover:bg-[#121B2D] cursor-pointer transition-colors"
                >
                  <td className="px-6 py-4">
                    <span className="text-white">{ticket.id}</span>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-[#94A3B8]">{ticket.customer}</span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <Smartphone className="w-4 h-4 text-[#64748B]" />
                      <span className="text-[#94A3B8]">{ticket.device}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className={`px-3 py-1 rounded-full text-xs border ${getStatusColor(ticket.status)}`}>
                      {ticket.status}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${getPriorityColor(ticket.priority)}`}></div>
                      <span className="text-[#94A3B8] text-sm capitalize">{ticket.priority}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="px-3 py-1 rounded-full text-xs bg-[#64748B]/10 text-[#94A3B8] border border-[#64748B]/20">
                      {ticket.sla}
                    </span>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      {ticket.deadline.includes('m') || (ticket.deadline.includes('h') && parseInt(ticket.deadline) < 4) ? (
                        <AlertCircle className="w-4 h-4 text-[#FF6B35]" />
                      ) : null}
                      <span className={`text-sm ${getDeadlineColor(ticket.deadline)}`}>
                        {ticket.deadline}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <span className="text-[#64748B] text-sm">{ticket.created}</span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
